return (function(a, b, c, d, e)
    for f = 0, 255 do
        a[b(f, 0)] = b(f)
    end

    function d(f, g, h, i)
        if h > 255 then
            h = 0
            i = i + 1

            if i > 255 then
                g = {}
                i = 1
            end
        end

        g[b(h, i)] = f
        h = h + 1

        return g, h, i
    end

    e = ({
        ([[]]):gsub('..', function(f)
            return b(tonumber(f, 16))
        end),
    })[1]

    local f, g, h, i, j, k, l = #e, {}, 0, 1, {}, 1, c(e, 1, 2)

    j[k] = a[l] or g[l]
    k = k + 1

    for m = 3, f, 2 do
        local n, o = c(e, m, m + 1), a[l] or g[l]
        local p = a[n] or g[n]

        if p then
            j[k] = p
            k = k + 1
            g, h, i = d(o .. c(p, 1, 1), g, h, i)
        else
            local q = o .. c(o, 1, 1)

            j[k] = q
            k = k + 1
            g, h, i = d(q, g, h, i)
        end

        l = n
    end

    return loadstring(table.concat(j))
end)({}, string.char, string.sub)(...)
